-- ============================================
-- Legislacao full-site: ivan-moraes / Recife OpenLegis / projetos_lei
-- Seed ampliado_parcial: autoria principal parlamentar municipal
-- ============================================
-- Fonte oficial:
--   https://publico.recife.pe.leg.br/consultas/materia
--   https://publico.recife.pe.leg.br/@@materias?ano={ano}&tipo={tipo}
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = ivan-moraes-recife-openlegis-autoria-principal-ampliado-parcial-20260507
--   coverage_scope = inventario_ampliado_parcial_recife_openlegis_autoria_principal_2017_2024_20260507
--
-- Filtro factual: OpenLegis oficial com autoria firstAuthor=true para Ivan Moraes,
-- tipos aceitos 10/14, numero/ano/ementa/PDF presentes e zero escrita em legislacao_mandato_executivo.

DO $$
DECLARE
  cand_id uuid;
  current_pl_count int;
  current_lme_count int;
  mandato_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'ivan-moraes' AND publicavel = true;

  IF cand_id IS NULL THEN
    RAISE NOTICE 'ivan-moraes: pre-condicao pulada porque candidato publico nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO current_pl_count FROM projetos_lei WHERE candidato_id = cand_id;
  SELECT count(*) INTO current_lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;

  IF current_pl_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao ivan-moraes: projetos_lei esperado 0, encontrado %', current_pl_count;
  END IF;

  IF current_lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao ivan-moraes: legislacao_mandato_executivo esperado 0, encontrado %', current_lme_count;
  END IF;

  SELECT count(*) INTO mandato_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND hp.tipo_evento = 'mandato'
    AND UPPER(COALESCE(hp.estado, '')) = 'PE'
    AND (hp.cargo ILIKE '%Vereador%' OR hp.cargo_canonico = 'Vereador')
    AND COALESCE(hp.periodo_inicio, 9999) <= 2024
    AND COALESCE(hp.periodo_fim, 0) >= 2017;

  IF mandato_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao ivan-moraes: mandato Vereador/Recife PE compativel com 2017-2024 nao encontrado';
  END IF;
END $$;

