WITH target AS (
  SELECT c.id AS candidato_id
  FROM candidatos c
  WHERE c.slug = 'ivan-moraes' AND c.publicavel = true
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM target
CROSS JOIN _seed_ivan_moraes_recife_openlegis_lote_a AS seed
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
WHERE projetos_lei.coverage_id IS NULL
   OR projetos_lei.coverage_id = EXCLUDED.coverage_id;

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  target_count int;
  coverage_count int;
  wrong_lme_count int;
  rejected_present_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'ivan-moraes' AND publicavel = true;

  IF cand_id IS NULL THEN
    RAISE NOTICE 'ivan-moraes: pos-condicao pulada porque candidato publico nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count FROM projetos_lei WHERE candidato_id = cand_id;
  SELECT count(*) INTO target_count FROM projetos_lei WHERE candidato_id = cand_id AND proposicao_id_api IN ('RECIFE-OPENLEGIS:208:TIPO-10:ID-157520', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-157211', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-155745', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-147937', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-145707', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-138554', 'RECIFE-OPENLEGIS:208:TIPO-14:ID-141210', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-133292', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-131874', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-130241', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-126710', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-125852', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-125644', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-125043', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-124854', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-123553', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-123452', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-121909', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-117165', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-115896', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-107171', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-105695', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-105573', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-105360', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-103942', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-103230', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-103229', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-103228', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-102469', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-102468', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-102360', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-102081', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-97300', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-95832', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-95343', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-94378', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-93772', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-91199', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-89479', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-89477', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-88256', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-81054', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-81053', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-76160', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-75424', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-74239', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-72057', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-72030', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-70716', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-69907');
  SELECT count(*) INTO coverage_count
