    AND coverage_scope = 'inventario_ampliado_parcial_recife_openlegis_autoria_principal_2017_2024_20260507';
  SELECT count(*) INTO wrong_lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  SELECT count(*) INTO rejected_present_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('RECIFE-OPENLEGIS:208:TIPO-10:ID-105154', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-105493', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-112905', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-116304', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-123775', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-123776', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-126837', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-127066', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-128485', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-137906', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-63402', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-69918', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-70722', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-71590', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-76256', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-81052', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-81055', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-81062', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-81988', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-82135', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-82440', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-82623', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-84204', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-85753', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-92955', 'RECIFE-OPENLEGIS:208:TIPO-10:ID-93785', 'RECIFE-OPENLEGIS:208:TIPO-2:ID-102359', 'RECIFE-OPENLEGIS:208:TIPO-2:ID-103613', 'RECIFE-OPENLEGIS:208:TIPO-2:ID-104166', 'RECIFE-OPENLEGIS:208:TIPO-2:ID-104651', 'RECIFE-OPENLEGIS:208:TIPO-2:ID-104890', 'RECIFE-OPENLEGIS:208:TIPO-2:ID-104891', 'RECIFE-OPENLEGIS:208:TIPO-2:ID-105566', 'RECIFE-OPENLEGIS:208:TIPO-2:ID-106076', 'RECIFE-OPENLEGIS:208:TIPO-2:ID-112515', 'RECIFE-OPENLEGIS:208:TIPO-2:ID-135411', 'RECIFE-OPENLEGIS:208:TIPO-2:ID-65843', 'RECIFE-OPENLEGIS:208:TIPO-2:ID-94520', 'RECIFE-OPENLEGIS:208:TIPO-2:ID-98301', 'RECIFE-OPENLEGIS:208:TIPO-6:ID-102334', 'RECIFE-OPENLEGIS:208:TIPO-6:ID-102458', 'RECIFE-OPENLEGIS:208:TIPO-6:ID-113215', 'RECIFE-OPENLEGIS:208:TIPO-6:ID-123213', 'RECIFE-OPENLEGIS:208:TIPO-6:ID-129307', 'RECIFE-OPENLEGIS:208:TIPO-6:ID-129308', 'RECIFE-OPENLEGIS:208:TIPO-6:ID-138424', 'RECIFE-OPENLEGIS:208:TIPO-6:ID-144636', 'RECIFE-OPENLEGIS:208:TIPO-6:ID-1485