  IF target_count <> 50 THEN
    RAISE EXCEPTION 'Pos-apply ivan-moraes: esperadas 50 rows alvo em projetos_lei, encontradas %', target_count;
  END IF;

  IF coverage_count <> 50 THEN
    RAISE EXCEPTION 'Pos-apply ivan-moraes: esperadas 50 rows com coverage_id/scope alvo, encontradas %', coverage_count;
  END IF;

  IF total_count <> 50 THEN
    RAISE EXCEPTION 'Pos-apply ivan-moraes: total projetos_lei esperado 50, encontrado %', total_count;
  END IF;

  IF wrong_lme_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply ivan-moraes: legislacao_mandato_executivo deveria permanecer 0, encontrado %', wrong_lme_count;
  END IF;

  IF rejected_present_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply ivan-moraes: % rejected rows foram inseridas indevidamente', rejected_present_count;
  END IF;

  RAISE NOTICE 'Pos-apply ivan-moraes OpenLegis Lote A: projetos_lei=% coverage_rows=%', total_count, coverage_count;
END $$;
